INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'dd9919ef-1707-426b-a7f8-d94637734673',
  '00000000-0000-0000-0000-000000000001',
  $escape$Node.js Error Handling — Exceptions vs Result Types and When to Use Each$escape$,
  $escape$Node.js leans on thrown exceptions and callback-style `(err, data)` patterns, but neither scales cleanly across async boundaries. `async/await` makes try/catch viable again, but swallowed rejections and deeply nested catch blocks are common pitfalls. Unhandled promise rejections now crash the process in Node 15+ — so missing a `catch` is a hard failure, not a silent bug.

A practical alternative is the Result pattern: return `{ ok: true, value }` or `{ ok: false, error }` instead of throwing. This makes error paths explicit at the call site and composes well with async code. Libraries like `neverthrow` bring Rust-style `Result<T, E>` to TypeScript, giving you `map`, `andThen`, and exhaustive matching without runtime overhead.

For propagation: throw only for truly exceptional, unrecoverable states (e.g. misconfigured env vars at startup). Use Result types for expected domain failures (validation, not-found, auth). Always attach `cause` when rethrowing: `throw new Error('DB write failed', { cause: err })` — Node's `Error.cause` chain is natively supported since v16.9 and surfaces cleanly in structured logs.$escape$,
  $escape$import { ok, err, Result } from 'neverthrow';

type UserError = 'NOT_FOUND' | 'DB_ERROR';

async function getUser(id: string): Promise<Result<User, UserError>> {
  try {
    const user = await db.users.findById(id);
    if (!user) return err('NOT_FOUND');
    return ok(user);
  } catch (e) {
    return err('DB_ERROR');
  }
}

// Call site — no try/catch needed, error path is explicit
const result = await getUser(userId);
if (result.isErr()) {
  if (result.error === 'NOT_FOUND') return res.status(404).json({ message: 'User not found' });
  throw new Error('Unexpected DB failure', { cause: result.error });
}
return res.json(result.value);$escape$,
  $escape$typescript$escape$,
