INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '030ee0f9-8bf0-4502-bd57-41d6f3b24989',
  '00000000-0000-0000-0000-000000000001',
  $escape$Node.js Unit Testing — Jest vs Node Test Runner and What to Pick$escape$,
  $escape$Node.js 18+ ships a built-in test runner (`node:test`) that eliminates the need for Jest in many scenarios. It supports `describe`/`it` blocks, `beforeEach`/`afterEach` hooks, mocking via `mock.fn()`, and runs with zero config using `node --test`. For most backend services — HTTP handlers, utility functions, repository logic — it's more than sufficient.

Jest still wins when you need snapshot testing, extensive matcher libraries, or seamless TypeScript integration without manual ts-node wiring. But for greenfield Node.js APIs, reaching for Jest by default is now cargo-culting.

The real unit testing philosophy in Node.js: test behavior, not implementation. Avoid mocking internal module internals — instead, inject dependencies via constructor arguments or function parameters so tests stay fast and honest. Use `assert.strictEqual` (built-in) or Jest's `expect` for assertions, but never mix both in one project. Keep each test file focused on a single module, mirror your `src/` structure under `__tests__/`, and run tests in parallel using `--test-concurrency` to keep CI tight.$escape$,
  $escape$// userService.test.js — using node:test (Node 18+)
import { describe, it, beforeEach, mock } from 'node:test';
import assert from 'node:assert/strict';
import { createUserService } from '../src/userService.js';

describe('createUserService', () => {
  let db;
  let service;

  beforeEach(() => {
    db = { findById: mock.fn(async (id) => ({ id, name: 'Alice' })) };
    service = createUserService(db);
  });

  it('returns user by id', async () => {
    const user = await service.getUser('123');
    assert.equal(user.name, 'Alice');
    assert.equal(db.findById.mock.calls.length, 1);
  });
});$escape$,
  $escape$javascript$escape$,
