INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '7422e3e6-02d0-4548-a893-1b8ffc9e8538',
  '00000000-0000-0000-0000-000000000001',
  $escape$Node.js Code Quality — ESLint Flat Config + Prettier Without the Fight$escape$,
  $escape$ESLint's new flat config (`eslint.config.js`) is now the default in ESLint v9, replacing `.eslintrc`. It's a plain JS module — no more JSON quirks, no more implicit cascading. Pair it with `eslint-config-prettier` to disable ESLint rules that conflict with Prettier, and you get a clean separation: ESLint catches bugs, Prettier owns formatting. For Node.js specifically, enable the `node` plugin (`eslint-plugin-n`) to catch real runtime issues: using `fs.promises` instead of callback-based `fs`, flagging `require()` of ESM-only packages, and enforcing engine-compatible syntax via `engines` in your `package.json`. Set `"type": "module"` in `package.json` and use `sourceType: "module"` in your flat config to enforce ESM idioms. Run both tools via a single `lint` script — never let formatting be a separate manual step. Use `--fix` in CI only on feature branches, never on main, to avoid noisy commits.$escape$,
  $escape$// eslint.config.js
import js from "@eslint/js";
import pluginN from "eslint-plugin-n";
import prettier from "eslint-config-prettier";

export default [
  js.configs.recommended,
  pluginN.configs["flat/recommended-module"],
  prettier,
  {
    rules: {
      "n/prefer-promises/fs": "error",
      "n/no-unsupported-features/node-builtins": "error",
      "no-console": ["warn", { allow: ["error"] }]
    }
  }
];$escape$,
  $escape$javascript$escape$,
