INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'b3f07a84-4a96-4d22-9b6b-9f26567d0f16',
  '00000000-0000-0000-0000-000000000001',
  $escape$Node.js Docker Images — Shrinking from 1GB to Under 100MB$escape$,
  $escape$The official `node:20` image weighs ~1.1GB. For production containers, that's wasteful. The fix: multi-stage builds with `node:20-alpine` as the final stage, copying only `node_modules` built for production and the compiled output — not your entire source tree.

Key moves: run `npm ci --omit=dev` in the build stage to strip devDependencies, then copy only the artifacts you need. For apps using native addons (e.g. `sharp`, `bcrypt`), pin the Alpine version and install `libc6-compat` — musl vs glibc mismatches are the silent killer here.

If you use `pkg` or `nexe` to produce a self-contained binary, you can drop to a `scratch` or `distroless/static` base — no Node runtime needed at all, final image under 50MB. For ESM-only projects, ensure your `package.json` sets `"type": "module"` before bundling with `esbuild --bundle --platform=node`, otherwise you'll hit CJS/ESM interop issues at runtime. Always set `NODE_ENV=production` — it disables Express dev middleware and cuts memory overhead by ~30%.$escape$,
  $escape$# syntax=docker/dockerfile:1
FROM node:20-alpine AS builder
WORKDIR /app
COPY package*.json ./
RUN npm ci --omit=dev
COPY . .
RUN npx esbuild src/index.ts --bundle --platform=node --outfile=dist/server.js

FROM node:20-alpine
WORKDIR /app
ENV NODE_ENV=production
COPY --from=builder /app/node_modules ./node_modules
COPY --from=builder /app/dist ./dist
EXPOSE 3000
CMD ["node", "dist/server.js"]$escape$,
  $escape$bash$escape$,
