INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'c34823fe-fb3f-4d37-a975-3c573901e389',
  '00000000-0000-0000-0000-000000000001',
  $escape$Node.js Dev Tooling — REPL, Inspector, and LSP in Your Daily Workflow$escape$,
  $escape$The Node.js REPL is more powerful than most developers use it. Launch it with `node --experimental-repl-await` to use top-level await interactively — no async wrapper needed. Use `.load script.js` to pull a file into the session, or `repl.start()` programmatically to embed a live REPL inside your running process for runtime introspection.

For debugging, `node --inspect` opens a V8 inspector on `127.0.0.1:9229`. Attach VS Code by adding `"type": "node", "request": "attach"` to your launch config, or hit `chrome://inspect` for DevTools. Use `--inspect-brk` to pause execution before your first line — essential for debugging startup logic or CLI entrypoints.

On the LSP front, `typescript-language-server` drives IntelliSense for both `.ts` and `.js` files in editors like Neovim and VS Code. A `jsconfig.json` with `"checkJs": true` and `"strict": true` enables type-checking without a full TypeScript migration. Pair with `@types/node` to get accurate typings for `fs`, `http`, `process`, and other core modules.$escape$,
  $escape$// .vscode/launch.json — attach to running Node.js inspector
{
  "version": "0.2.0",
  "configurations": [
    {
      "type": "node",
      "request": "attach",
      "name": "Attach to Node",
      "port": 9229,
      "restart": true,
      "skipFiles": ["<node_internals>/**"]
    }
  ]
}

// Start your app with:
// node --inspect src/index.js$escape$,
  $escape$javascript$escape$,
