INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'be6ae772-e442-4c36-89ad-1f8a230f7292',
  '00000000-0000-0000-0000-000000000001',
  $escape$Node.js Event Loop — Phases, Microtasks, and Why Order Matters$escape$,
  $escape$The Node.js event loop isn't a single queue — it's six ordered phases: timers, pending callbacks, idle/prepare, poll, check, and close callbacks. Most developers only think about timers and I/O, but the phase order has real consequences.

Microtasks (Promise callbacks, queueMicrotask()) drain completely between every phase transition and between each individual timer/setImmediate callback. This means a recursive Promise chain can starve I/O indefinitely. process.nextTick() sits in its own microtask queue and runs before Promises — overusing it will block the event loop just as effectively as synchronous code.

setImmediate() fires in the check phase, after the poll phase completes. setTimeout(fn, 0) fires in the timers phase. When called from the main module they race; inside an I/O callback setImmediate() always wins because the event loop is already past timers.

Use --inspect with chrome://inspect and the 'Performance' tab to visualize actual phase durations. For CPU-heavy work, offload to worker_threads — they run a full independent event loop, not a thread pool slot.$escape$,
  $escape$const { Worker, isMainThread, parentPort } = require('worker_threads');

if (isMainThread) {
  // setImmediate always beats setTimeout(fn,0) inside an I/O callback
  const fs = require('fs');
  fs.readFile(__filename, () => {
    setTimeout(() => console.log('timer'), 0);
    setImmediate(() => console.log('immediate')); // always first
  });

  // Microtask starvation demo — don't do this
  // function loop() { Promise.resolve().then(loop); } loop();

  // Correct: offload CPU work
  const worker = new Worker(__filename);
  worker.on('message', (result) => console.log('worker result:', result));
} else {
  // Runs in its own event loop
  const result = Array.from({ length: 1e6 }, (_, i) => i).reduce((a, b) => a + b, 0);
  parentPort.postMessage(result);
}$escape$,
  $escape$javascript$escape$,
